-- ============================================================================
-- Vonai — APLICAR TODAS AS PENDÊNCIAS DE UMA VEZ
-- Cole TUDO no Supabase -> SQL Editor -> RUN. Seguro rodar mais de uma vez.
-- Inclui: gamificação, uso/custo IA, liga semanal, feedback e +92 lições novas.
-- (perfil_ia, push_subscriptions e supabase_fix_progresso já foram aplicados.)
-- ============================================================================
begin;

-- 1) Gamificação: moedas e proteção de sequência ----------------------------
alter table progresso add column if not exists moedas integer default 0;
alter table progresso add column if not exists streak_freezes integer default 0;

-- 2) Uso/custo da IA (trava diária no servidor) -----------------------------
alter table progresso add column if not exists chat_dia_data text;
alter table progresso add column if not exists chat_dia_count integer default 0;

-- 3) Liga semanal (ranking de XP) -------------------------------------------
alter table progresso add column if not exists nome text;
alter table progresso add column if not exists sem_num integer default 0;
alter table progresso add column if not exists sem_base_xp integer default 0;
alter table progresso add column if not exists sem_xp integer default 0;
create or replace view ranking_semanal
  with (security_invoker = off) as
  select nome, sem_num, sem_xp
  from progresso
  where nome is not null;
grant select on ranking_semanal to anon, authenticated;

-- 4) Caixa de feedback dos alunos -------------------------------------------
create table if not exists public.feedback (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id) on delete set null,
  email text,
  mensagem text not null,
  created_at timestamptz default now()
);
alter table public.feedback enable row level security;
drop policy if exists "feedback_insert_own" on public.feedback;
create policy "feedback_insert_own" on public.feedback
  for insert to authenticated
  with check (auth.uid() = user_id);

-- 5) Lições novas (+80 lotes 1-4 e +12 do C2) -------------------------------
-- Limpa antes para poder reaplicar sem duplicar (ordem 3001-3080 e 1111-1122).
delete from licoes where ordem between 3001 and 3080;
delete from licoes where ordem between 1111 and 1122;

