('B1', 3041, $$Win x Beat$$, $$ganhar (algo) x vencer (alguém)$$, $$🏆$$,
$$WIN = ganhar um prêmio/jogo/competição (win a game, win a prize). BEAT = vencer/derrotar um oponente (beat someone). Não diga 'win someone'.$$,
$$You win a match, but you beat a team. Beat = derrotar alguém.$$,
$j$[{"en": "We won the game.", "pt": "Ganhamos o jogo."}, {"en": "They beat us 2-0.", "pt": "Eles nos venceram por 2 a 0."}, {"en": "She won a gold medal.", "pt": "Ela ganhou uma medalha de ouro."}]$j$::jsonb,
$j$[{"q": "'Vencemos o time deles' =", "ctx": "", "opts": ["We beat their team", "We won their team", "We win their team", "We beat the game"], "ans": 0, "exp": "beat + oponente."}, {"q": "'Ganhamos o jogo' =", "ctx": "", "opts": ["We won the game", "We beat the game", "We win the game only", "We won us"], "ans": 0, "exp": "win + jogo."}, {"q": "Qual está errado?", "ctx": "", "opts": ["I won you", "I beat you", "I won the prize", "They beat us"], "ans": 0, "exp": "'win you' não existe."}, {"q": "Passado de 'win':", "ctx": "", "opts": ["won", "winned", "win", "wan"], "ans": 0, "exp": "win -> won."}, {"q": "Passado de 'beat':", "ctx": "", "opts": ["beat", "beated", "bet", "beaten only"], "ans": 0, "exp": "beat -> beat."}, {"q": "'Ganhar um prêmio' =", "ctx": "", "opts": ["win a prize", "beat a prize", "win a person", "beat a game"], "ans": 0, "exp": "win a prize."}]$j$::jsonb),
('A2', 3042, $$Fun x Funny$$, $$divertido x engraçado$$, $$😄$$,
$$FUN = divertido/prazeroso (algo que dá prazer). FUNNY = engraçado (que faz rir) — ou estranho. Não confunda: uma festa é 'fun'; uma piada é 'funny'.$$,
$$The party was fun. / The joke was funny. 'Funny' também pode ser 'estranho'.$$,
$j$[{"en": "The trip was so much fun.", "pt": "A viagem foi muito divertida."}, {"en": "That comedian is really funny.", "pt": "Aquele comediante é muito engraçado."}, {"en": "This tastes funny.", "pt": "Isto tem um gosto estranho."}]$j$::jsonb,
$j$[{"q": "'A festa foi divertida' =", "ctx": "", "opts": ["The party was fun", "The party was funny", "The party is funny", "The party fun"], "ans": 0, "exp": "fun = divertido."}, {"q": "'Ele é engraçado' (faz rir) =", "ctx": "", "opts": ["He is funny", "He is fun", "He is funs", "He funny"], "ans": 0, "exp": "funny = engraçado."}, {"q": "FUN significa:", "ctx": "", "opts": ["divertido/prazeroso", "engraçado só", "estranho", "chato"], "ans": 0, "exp": "divertido."}, {"q": "'Uma piada engraçada' =", "ctx": "", "opts": ["a funny joke", "a fun joke", "a funny fun", "a joke fun"], "ans": 0, "exp": "funny joke."}, {"q": "'Funny' também pode significar:", "ctx": "", "opts": ["estranho", "triste", "caro", "rápido"], "ans": 0, "exp": "estranho."}, {"q": "'Foi super divertido' =", "ctx": "", "opts": ["It was a lot of fun", "It was a lot of funny", "It was many fun", "It was fun funny"], "ans": 0, "exp": "a lot of fun."}]$j$::jsonb),
('B1', 3043, $$Miss: perder x sentir falta$$, $$miss the bus / miss you$$, $$🚌$$,
$$MISS tem dois sentidos: perder (não pegar/alcançar) — miss the bus, miss a class; e sentir falta/saudade — I miss you.$$,
$$miss the bus = perder o ônibus; I miss you = sinto sua falta.$$,
$j$[{"en": "I missed the bus this morning.", "pt": "Perdi o ônibus hoje de manhã."}, {"en": "I miss you so much.", "pt": "Sinto muito a sua falta."}, {"en": "Don't miss this chance.", "pt": "Não perca esta chance."}]$j$::jsonb,
$j$[{"q": "'Perdi o ônibus' =", "ctx": "", "opts": ["I missed the bus", "I lost the bus", "I miss the bus yesterday", "I lost bus"], "ans": 0, "exp": "miss (não pegar)."}, {"q": "'Sinto sua falta' =", "ctx": "", "opts": ["I miss you", "I lost you", "I miss of you", "I feel your miss"], "ans": 0, "exp": "miss you."}, {"q": "'Perder uma aula' =", "ctx": "", "opts": ["miss a class", "lose a class", "miss of a class", "lost a class"], "ans": 0, "exp": "miss a class."}, {"q": "MISS pode significar:", "ctx": "", "opts": ["perder OU sentir falta", "só ganhar", "só ouvir", "comprar"], "ans": 0, "exp": "dois sentidos."}, {"q": "'Não perca a chance' =", "ctx": "", "opts": ["Don't miss the chance", "Don't lose the chance only", "Don't miss of chance", "Miss not chance"], "ans": 0, "exp": "miss the chance."}, {"q": "Para 'perder' objeto (chaves) usa-se:", "ctx": "", "opts": ["lose", "miss", "fail", "drop only"], "ans": 0, "exp": "lose (miss = não pegar)."}]$j$::jsonb),
('B2', 3044, $$Affect x Effect$$, $$afetar (verbo) x efeito (subst.)$$, $$🎯$$,
