('C2', 1111, $$Binômios fixos$$, $$back and forth, sooner or later$$, $$🔁$$,
$$Binômios são pares de palavras em ordem fixa ligados por "and" ou "or". Invertê-los soa estranho para nativos.$$,
$$A ordem é fixa: dizemos "salt and pepper", nunca "pepper and salt".$$,
$j$[{"en":"They walked back and forth nervously.","pt":"Andaram de um lado para o outro, nervosos."},{"en":"Sooner or later, you will understand.","pt":"Mais cedo ou mais tarde você vai entender."},{"en":"By and large, the plan worked.","pt":"De modo geral, o plano funcionou."}]$j$::jsonb,
$j$[{"q":"Complete: salt and ___","ctx":"","opts":["pepper","sugar","water","bread"],"ans":0,"exp":"salt and pepper (ordem fixa)."},{"q":"'Sooner or later' significa:","ctx":"","opts":["mais cedo ou mais tarde","agora mesmo","nunca","talvez"],"ans":0,"exp":"Cedo ou tarde."},{"q":"'By and large' =","ctx":"","opts":["de modo geral","com força","aos poucos","de repente"],"ans":0,"exp":"Em geral."},{"q":"Binômio para 'sãos e salvos':","ctx":"","opts":["safe and sound","sound and safe","safe or sound","sound and safe"],"ans":0,"exp":"safe and sound."},{"q":"'Pros and cons' =","ctx":"","opts":["prós e contras","idas e vindas","altos e baixos","ganhos e perdas"],"ans":0,"exp":"Vantagens e desvantagens."},{"q":"O que define um binômio fixo?","ctx":"","opts":["a ordem das palavras é fixa","pode inverter livremente","tem três palavras","é sempre formal"],"ans":0,"exp":"Ordem consagrada."}]$j$::jsonb),
('C2', 1112, $$Idioms de negócios$$, $$ballpark figure, touch base$$, $$💼$$,
