$j$[{"en":"Let us touch base next week.","pt":"Vamos nos alinhar na próxima semana."},{"en":"Can you give me a ballpark figure?","pt":"Pode me dar um valor aproximado?"},{"en":"We need to think outside the box.","pt":"Precisamos pensar de forma criativa."}]$j$::jsonb,
